import{_ as n,c as l,o as a,a1 as t,j as e,a as o,t as r}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse(`{"title":"Introduction: OpenCode Agent Skills | opencode-agent-skills","description":"Apprenez les valeurs fondamentales et les fonctionnalités principales d'OpenCode Agent Skills. Maîtrisez la découverte dynamique de skills, l'injection de contexte, la compression et la récupération, compatible avec Claude Code et recommandations automatiques.","frontmatter":{"title":"Introduction: OpenCode Agent Skills | opencode-agent-skills","sidebarTitle":"Faire comprendre vos skills à l'IA","subtitle":"Introduction: OpenCode Agent Skills","description":"Apprenez les valeurs fondamentales et les fonctionnalités principales d'OpenCode Agent Skills. Maîtrisez la découverte dynamique de skills, l'injection de contexte, la compression et la récupération, compatible avec Claude Code et recommandations automatiques.","tags":["Guide de démarrage","Introduction au plugin"],"prerequisite":[],"order":1},"headers":[],"relativePath":"fr/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md","filePath":"fr/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md"}`),d={name:"fr/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md"},u={tabindex:"0"};function c(i,s,p,m,g,h){return a(),l("div",null,[s[7]||(s[7]=t(`<h1 id="qu-est-ce-qu-opencode-agent-skills" tabindex="-1">Qu&#39;est-ce qu&#39;OpenCode Agent Skills ? <a class="header-anchor" href="#qu-est-ce-qu-opencode-agent-skills" aria-label="Permalink to &quot;Qu&#39;est-ce qu&#39;OpenCode Agent Skills ?&quot;">​</a></h1><h2 id="ce-que-vous-pourrez-faire-apres-ce-tutoriel" tabindex="-1">Ce que vous pourrez faire après ce tutoriel <a class="header-anchor" href="#ce-que-vous-pourrez-faire-apres-ce-tutoriel" aria-label="Permalink to &quot;Ce que vous pourrez faire après ce tutoriel&quot;">​</a></h2><ul><li>Comprendre les valeurs fondamentales du plugin OpenCode Agent Skills</li><li>Maîtriser les fonctionnalités principales fournies par le plugin</li><li>Comprendre comment les skills sont découverts et chargés automatiquement</li><li>Distinguer ce plugin des autres solutions de gestion de skills</li></ul><h2 id="les-problemes-que-vous-rencontrez-actuellement" tabindex="-1">Les problèmes que vous rencontrez actuellement <a class="header-anchor" href="#les-problemes-que-vous-rencontrez-actuellement" aria-label="Permalink to &quot;Les problèmes que vous rencontrez actuellement&quot;">​</a></h2><p>Vous avez peut-être rencontré ces situations :</p><ul><li><strong>Difficulté de gestion des skills dispersés</strong> : Les skills sont dispersés dans plusieurs emplacements (projet, répertoire utilisateur, cache du plugin), et vous ne trouvez pas le skill approprié</li><li><strong>Problèmes avec les sessions longues</strong> : Après une longue session, les skills chargés précédemment deviennent invalides à cause de la compression du contexte</li><li><strong>Anxiété de compatibilité</strong> : Inquiétude que les skills et plugins existants ne fonctionnent plus après la migration depuis Claude Code</li><li><strong>Configuration répétitive</strong> : Chaque projet nécessite une reconfiguration des skills, manque d&#39;un mécanisme de gestion unifié</li></ul><p>Ces problèmes affectent votre efficacité d&#39;utilisation des assistants IA.</p><h2 id="approche-fondamentale" tabindex="-1">Approche fondamentale <a class="header-anchor" href="#approche-fondamentale" aria-label="Permalink to &quot;Approche fondamentale&quot;">​</a></h2><p><strong>OpenCode Agent Skills</strong> est un système de plugin qui fournit à OpenCode des capacités de découverte et de gestion dynamiques des skills.</p><div class="info custom-block"><p class="custom-block-title">Qu&#39;est-ce qu&#39;un skill ?</p><p>Un skill (compétence) est un module réutilisable contenant des directives de workflow IA. C&#39;est généralement un répertoire contenant un fichier <code>SKILL.md</code> (décrivant les fonctionnalités et l&#39;utilisation du skill), ainsi que des fichiers auxiliaires possibles (documentation, scripts, etc.).</p></div><p><strong>Valeur fondamentale</strong> : Grâce au format de skill standardisé (SKILL.md), réaliser la réutilisation des skills entre projets et sessions.</p><h3 id="architecture-technique" tabindex="-1">Architecture technique <a class="header-anchor" href="#architecture-technique" aria-label="Permalink to &quot;Architecture technique&quot;">​</a></h3><p>Le plugin est développé en TypeScript + Bun + Zod, fournissant 4 outils de base :</p><table tabindex="0"><thead><tr><th>Outil</th><th>Fonction</th></tr></thead><tbody><tr><td><code>use_skill</code></td><td>Injecter le contenu SKILL.md du skill dans le contexte de session</td></tr><tr><td><code>read_skill_file</code></td><td>Lire les fichiers de support du répertoire du skill (documentation, configuration, etc.)</td></tr><tr><td><code>run_skill_script</code></td><td>Exécuter des scripts exécutables dans le contexte du répertoire du skill</td></tr><tr><td><code>get_available_skills</code></td><td>Obtenir la liste des skills actuellement disponibles</td></tr></tbody></table><h2 id="fonctionnalites-principales" tabindex="-1">Fonctionnalités principales <a class="header-anchor" href="#fonctionnalites-principales" aria-label="Permalink to &quot;Fonctionnalités principales&quot;">​</a></h2><h3 id="_1-decouverte-dynamique-des-skills" tabindex="-1">1. Découverte dynamique des skills <a class="header-anchor" href="#_1-decouverte-dynamique-des-skills" aria-label="Permalink to &quot;1. Découverte dynamique des skills&quot;">​</a></h3><p>Le plugin découvre automatiquement les skills à partir de plusieurs emplacements, triés par priorité :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. .opencode/skills/              (niveau projet - OpenCode)</span></span>
<span class="line"><span>2. .claude/skills/                (niveau projet - Claude Code)</span></span>
<span class="line"><span>3. ~/.config/opencode/skills/     (niveau utilisateur - OpenCode)</span></span>
<span class="line"><span>4. ~/.claude/skills/              (niveau utilisateur - Claude Code)</span></span>
<span class="line"><span>5. ~/.claude/plugins/cache/        (cache plugin)</span></span>
<span class="line"><span>6. ~/.claude/plugins/marketplaces/ (plugins installés)</span></span></code></pre></div><p><strong>Règle</strong> : La première occurrence du skill est appliquée, les occurrences ultérieures du même nom sont ignorées.</p><blockquote><p>Pourquoi cette conception ?</p><p>Les skills au niveau projet ont la priorité sur ceux au niveau utilisateur, vous permettant de personnaliser des comportements spécifiques dans un projet sans affecter la configuration globale.</p></blockquote><h3 id="_2-injection-de-contexte" tabindex="-1">2. Injection de contexte <a class="header-anchor" href="#_2-injection-de-contexte" aria-label="Permalink to &quot;2. Injection de contexte&quot;">​</a></h3><p>Lorsque vous appelez <code>use_skill</code>, le contenu du skill est injecté dans le contexte de session au format XML :</p><ul><li><code>noReply: true</code> - L&#39;IA ne répondra pas au message injecté</li><li><code>synthetic: true</code> - Marqué comme message généré par le système (non affiché dans l&#39;interface, non comptabilisé dans l&#39;entrée utilisateur)</li></ul><p>Cela signifie que le contenu du skill persiste dans le contexte de session, même lorsque la session grandit et subit une compression de contexte, le skill reste toujours disponible.</p><h3 id="_3-mecanisme-de-recuperation-apres-compression" tabindex="-1">3. Mécanisme de récupération après compression <a class="header-anchor" href="#_3-mecanisme-de-recuperation-apres-compression" aria-label="Permalink to &quot;3. Mécanisme de récupération après compression&quot;">​</a></h3><p>Lorsqu&#39;OpenCode effectue une compression de contexte (opération courante dans les sessions longues), le plugin écoute l&#39;événement <code>session.compacted</code>, et réinjecte automatiquement la liste des skills disponibles.</p><p>Cela garantit que l&#39;IA sait toujours quels skills sont disponibles pendant les sessions longues, sans perdre l&#39;accès aux skills à cause de la compression.</p><h3 id="_4-compatibilite-claude-code" tabindex="-1">4. Compatibilité Claude Code <a class="header-anchor" href="#_4-compatibilite-claude-code" aria-label="Permalink to &quot;4. Compatibilité Claude Code&quot;">​</a></h3><p>Le plugin est entièrement compatible avec le système de skills et de plugins de Claude Code, supportant :</p><ul><li>Skills Claude Code (<code>.claude/skills/&lt;nom-du-skill&gt;/SKILL.md</code>)</li><li>Cache de plugins Claude (<code>~/.claude/plugins/cache/...</code>)</li><li>Marketplace de plugins Claude (<code>~/.claude/plugins/marketplaces/...</code>)</li></ul><p>Cela signifie que si vous utilisiez Claude Code auparavant, vous pouvez toujours utiliser les skills et plugins existants après migration vers OpenCode.</p><h3 id="_5-recommandation-automatique-de-skills" tabindex="-1">5. Recommandation automatique de skills <a class="header-anchor" href="#_5-recommandation-automatique-de-skills" aria-label="Permalink to &quot;5. Recommandation automatique de skills&quot;">​</a></h3><p>Le plugin surveille vos messages, utilisant la détection de similarité sémantique pour déterminer si un skill disponible est pertinent :</p><ul><li>Calculer le vecteur d&#39;embedding du message</li><li>Calculer la similarité cosinus avec la description de tous les skills</li><li>Lorsque la similarité dépasse le seuil, injecter une invite d&#39;évaluation suggérant à l&#39;IA de charger le skill pertinent</li></ul><p>Ce processus est entièrement automatique, vous n&#39;avez pas besoin de mémoriser les noms de skills ou de faire des demandes explicites.</p><h3 id="_6-integration-superpowers-optionnel" tabindex="-1">6. Intégration Superpowers (optionnel) <a class="header-anchor" href="#_6-integration-superpowers-optionnel" aria-label="Permalink to &quot;6. Intégration Superpowers (optionnel)&quot;">​</a></h3><p>Le plugin supporte le workflow Superpowers, activable via variable d&#39;environnement :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> opencode</span></span></code></pre></div><p>Après activation, le plugin détectera automatiquement le skill <code>using-superpowers</code> et injectera les directives complètes du workflow lors de l&#39;initialisation de la session.</p><h2 id="comparaison-avec-d-autres-solutions" tabindex="-1">Comparaison avec d&#39;autres solutions <a class="header-anchor" href="#comparaison-avec-d-autres-solutions" aria-label="Permalink to &quot;Comparaison avec d&#39;autres solutions&quot;">​</a></h2>`,40)),e("table",u,[s[6]||(s[6]=e("thead",null,[e("tr",null,[e("th",null,"Solution"),e("th",null,"Caractéristiques"),e("th",null,"Scénario d'application")])],-1)),e("tbody",null,[s[3]||(s[3]=e("tr",null,[e("td",null,[e("strong",null,"opencode-agent-skills")]),e("td",null,"Découverte dynamique, récupération après compression, recommandation automatique"),e("td",null,"Scénarios nécessitant une gestion unifiée et des recommandations automatiques")],-1)),e("tr",null,[s[1]||(s[1]=e("td",null,[e("strong",null,"opencode-skills")],-1)),e("td",null,[s[0]||(s[0]=o("Enregistrement automatique en tant qu'outil ",-1)),e("code",null,"skills_"+r(i.nom),1)]),s[2]||(s[2]=e("td",null,"Scénarios nécessitant des appels d'outils indépendants",-1))]),s[4]||(s[4]=e("tr",null,[e("td",null,[e("strong",null,"superpowers")]),e("td",null,"Workflow complet de développement logiciel"),e("td",null,"Projets nécessitant des processus stricts")],-1)),s[5]||(s[5]=e("tr",null,[e("td",null,[e("strong",null,"skillz")]),e("td",null,"Mode serveur MCP"),e("td",null,"Scénarios nécessitant l'utilisation de skills à travers des outils")],-1))])]),s[8]||(s[8]=t('<p>Raisons de choisir ce plugin :</p><ul><li>✅ <strong>Zéro configuration</strong> : découverte et gestion automatiques des skills</li><li>✅ <strong>Recommandation intelligente</strong> : recommandation automatique de skills pertinents basée sur la correspondance sémantique</li><li>✅ <strong>Récupération après compression</strong> : stable et fiable pendant les sessions longues</li><li>✅ <strong>Compatibilité</strong> : migration transparente des skills Claude Code</li></ul><h2 id="resume-de-cette-lecon" tabindex="-1">Résumé de cette leçon <a class="header-anchor" href="#resume-de-cette-lecon" aria-label="Permalink to &quot;Résumé de cette leçon&quot;">​</a></h2><p>Le plugin OpenCode Agent Skills fournit des capacités complètes de gestion des skills à OpenCode grâce aux mécanismes de découverte dynamique, d&#39;injection de contexte et de récupération après compression. Ses valeurs fondamentales sont :</p><ul><li><strong>Automatisation</strong> : réduire le fardeau de la configuration manuelle et de la mémorisation des noms de skills</li><li><strong>Stabilité</strong> : les skills restent toujours disponibles pendant les sessions longues</li><li><strong>Compatibilité</strong> : intégration transparente avec l&#39;écosystème Claude Code existant</li></ul><h2 id="apercu-de-la-prochaine-lecon" tabindex="-1">Aperçu de la prochaine leçon <a class="header-anchor" href="#apercu-de-la-prochaine-lecon" aria-label="Permalink to &quot;Aperçu de la prochaine leçon&quot;">​</a></h2><blockquote><p>Dans la prochaine leçon, nous apprendrons <strong><a href="./../installation/">l&#39;installation d&#39;OpenCode Agent Skills</a></strong>.</p><p>Vous apprendrez :</p><ul><li>Comment ajouter le plugin dans la configuration OpenCode</li><li>Comment vérifier si le plugin est correctement installé</li><li>La méthode de configuration du mode développement local</li></ul></blockquote><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour voir l&#39;emplacement du code source</strong></summary><blockquote><p>Dernière mise à jour : 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Fonctionnalité</th><th>Chemin du fichier</th><th>Lignes</th></tr></thead><tbody><tr><td>Entrée du plugin et vue d&#39;ensemble des fonctionnalités</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L1-L12" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>1-12</td></tr><tr><td>Liste des fonctionnalités principales</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/README.md#L5-L11" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>5-11</td></tr><tr><td>Priorité de découverte des skills</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L241-L246" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>241-246</td></tr><tr><td>Injection de messages synthétiques</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L147-L162" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>147-162</td></tr><tr><td>Mécanisme de récupération après compression</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L144-L151" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>144-151</td></tr><tr><td>Module de correspondance sémantique</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/embeddings.ts#L108-L135" target="_blank" rel="noreferrer"><code>src/embeddings.ts</code></a></td><td>108-135</td></tr></tbody></table><p><strong>Constantes clés</strong> :</p><ul><li><code>EMBEDDING_MODEL = &quot;Xenova/all-MiniLM-L6-v2&quot;</code> : modèle d&#39;embedding utilisé</li><li><code>SIMILARITY_THRESHOLD = 0.35</code> : seuil de similarité sémantique</li><li><code>TOP_K = 5</code> : nombre maximum de skills retournés par la recommandation automatique</li></ul><p><strong>Fonctions clés</strong> :</p><ul><li><code>discoverAllSkills()</code> : découvrir les skills à partir de plusieurs emplacements</li><li><code>use_skill()</code> : injecter le contenu du skill dans le contexte de session</li><li><code>matchSkills()</code> : faire correspondre les skills pertinents basés sur la similarité sémantique</li><li><code>injectSyntheticContent()</code> : injecter des messages synthétiques dans la session</li></ul></details>',10))])}const f=n(d,[["render",c]]);export{b as __pageData,f as default};
